import{_ as m,o as a,c as r,F as g,B as h,j as e,t as o,k as c,d as b,a as i,E as d}from"./chunks/framework.Co1PSFSm.js";const l=JSON.parse('[{"title":"index","content":"<script setup lang=\\"ts\\">\\nimport BlogList from \'./components/BlogList.vue\'\\n\\n<\/script>\\n\\n\\n# 博客\\n\\n这是我的技术博客页面，记录了我的编程经验、技术思考和项目实践。\\n\\n## 文章列表\\n\\n<BlogList/>","lastUpdated":1778834143483},{"title":"开发了一个APP，我叫它minebook-hot-server","content":"# MineBook Hot Server：个人开发的本地服务智能管理工具\\n\\n**MineBook Hot Server** 是我个人开发的一款用于管理本地开发服务的自动化工具，用于智能监控和管理本地端口，有效减少不必要的系统资源占用。\\n\\n## 背景与需求\\n\\n在我日常的开发工作中，我遇到了一些痛点：\\n\\n- 本地服务端口被占用时，我很难快速定位是哪个进程在运行\\n- 偶尔启动的服务在使用完毕后，我经常会忘记手动关闭\\n- 这些未关闭的服务导致我的电脑内存压力一直很高\\n- 长期下来，我的 MacBook 就会因为内存不足而变得卡顿\\n- 当内存不足时，MacBook 会启用虚拟内存，将硬盘作为交换空间，这样会影响硬盘寿命\\n\\n我相信其他开发者也可能面临类似的困扰。\\n\\n## 个人解决方案\\n\\n作为独立开发者，我设计并开发了 **MineBook Hot Server** 来解决我自己遇到的这些问题：\\n\\n- 智能管理系统资源分配，确保充足可用内存\\n- 优化系统性能，专注当前任务处理\\n- 预防系统卡顿，提升开发体验\\n\\n## 技术实现方案\\n\\n该工具基于 Tauri 构建，采用 Rust 作为后端语言，前端使用 Web 技术实现。核心技术方案如下：\\n\\n- 后台轮询监听端口流量：系统定期扫描指定端口的流量情况\\n- 活跃度判断：通过检测端口流量变化来判断服务是否处于活跃状态\\n- 智能关闭：如果端口在设定时间内（如30秒）没有流量变化，则判定为不活跃\\n- 进程管理：对不活跃的端口进行 PID 反查，并自动发送终止命令\\n\\n## 核心功能实现\\n\\n### 传统方式对比\\n\\n我之前在开发时，通常会通过命令行启动多个端口服务（例如 8888 和 9999 端口），但这种方式让我感到不便：\\n\\n- 需要频繁打开终端控制台\\n- 服务生命周期完全依赖手动管理，我经常忘记关闭这些服务\\n- 长期运行的服务持续占用内存资源\\n\\n### 项目工作流程\\n\\n为了解决我的这个问题，我在该工具中实现了图形化界面，简化了我的服务管理流程：\\n\\n1. 通过 **MineBook Server App** 点击\\"添加服务\\"\\n2. 配置启动命令及相关参数\\n3. 保存配置后应用自动托管对应端口\\n4. 我可以直接通过界面访问服务，无需操作控制台\\n\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-1.png)\\n\\n### 智能闲置管理算法\\n\\n针对我自己的使用习惯，系统具备自动检测功能：\\n\\n- 实时监测端口流量以判断服务活跃状态\\n- 根据预设策略自动关闭我不再使用的端口\\n- 例如，9999 端口在我连续 30 秒没有访问后会自动关闭\\n\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-2.png)\\n\\n## 个人开发总结\\n\\n**MineBook Hot Server** 是我独立设计和实现的项目。从概念设计到功能实现，再到实际部署，整个项目完全由我个人完成。经过一段时间的实际使用验证，该工具在以下方面表现出色：\\n\\n- 有效控制内存占用\\n- 清晰展示当前活跃的本地端口信息\\n- 基于 RAS 架构，保证了系统的稳定性\\n\\n如果你也常常为本地服务管理而烦恼，不妨关注我的技术分享，了解这款工具的最新进展。我正在持续优化中，未来版本将增加更多实用功能。欢迎试用并提出宝贵意见，帮助我进一步完善这个工具！","lastUpdated":1778808690228},{"title":"macOS安装whisper进行语音识别","content":"---\\ntitle: 在 macOS 上安装 Whisper 进行语音识别\\n---\\n<!-- ![alt text](blog-imgs/macOS安装whisper进行语音识别/image.png) -->\\n\\n# 在 macOS 上安装 Whisper 进行语音识别\\n\\n## 第一步：安装 Homebrew\\n\\nHomebrew 是一个开源的软件包管理工具，非常适合在 macOS 系统上使用。\\n\\n> 如果您已经安装了 Homebrew，可以跳过此步骤。\\n\\n### 安装过程\\n\\n1. 访问 [Homebrew 官网](https://brew.sh/)\\n2. 复制官网提供的安装命令\\n3. 粘贴到终端中并回车执行\\n\\n<!-- ![alt text](../public/blog-imgs/macOS安装whisper进行语音识别/image-1.png) -->\\n\\n安装前系统会向您确认安装内容，再次回车即可开始安装。\\n\\n> **注意**：下载过程可能比较耗时，请耐心等待。\\n\\n### 配置环境变量\\n\\n安装完成后，您需要配置环境变量，否则执行命令时可能会报错。\\n\\n配置环境变量很简单，只需执行终端提示的脚本命令即可：\\n\\n```bash\\n# 示例命令，请以官网最新提示为准\\neval \\"$(/opt/homebrew/bin/brew shellenv)\\"\\n```\\n\\n执行完成后，您就可以正常使用 brew 命令了。\\n\\n> 成功完成此步骤后，整个安装过程就完成了一大半。\\n\\n## 第二步：下载 Whisper 的语音模型\\n\\n官方提供了 tiny、base、small、medium、large 五种不同规格的语音模型。\\n\\n| 模型 | 适用场景 | 特点 |\\n|------|----------|------|\\n| tiny | 快速测试 | 最小 |\\n| base | 一般用途 | 小巧 |\\n| small | 一般用途 | 推荐 |\\n| medium | 高精度需求 | 较大 |\\n| large | 最高精度 | 最大 |\\n\\n对于一般用途，推荐选择 **small** 模型。虽然只有几百 MB，但中文识别准确度很高。\\n\\n### 下载模型\\n\\n1. 访问 Whisper 模型下载页面 (例如 [huggingface.co/ggerganov/whisper.cpp](https://huggingface.co/ggerganov/whisper.cpp))\\n2. 找到 `ggml-small.bin` 文件\\n3. 点击下载\\n\\n<!-- ![alt text](../public/blog-imgs/macOS安装whisper进行语音识别/image-2.png) -->\\n\\n下载完成后，请将模型文件保存在一个容易访问的目录中备用。\\n\\n## 第三步：安装 Whisper\\n\\n由于我们之前安装了 Homebrew，现在只需执行以下命令即可完成安装：\\n\\n```bash\\nbrew install whisper\\n```\\n\\n> **注意**：安装过程中可能会出现网络问题，可以重试或尝试使用代理。\\n\\n## 如何使用 Whisper\\n\\nWhisper 官方提供了多种使用方式，下面介绍一种最简单的用法：**whisper-server**。\\n\\n### 启动 Whisper Server\\n\\nwhisper-server 是官方自带的可视化界面，可以直接在浏览器中打开，操作方便。\\n\\n执行以下命令启动服务：\\n\\n```bash\\nwhisper-server --model /path/to/ggml-small.bin\\n```\\n\\n> **重要**：请将命令中的 `/path/to/ggml-small.bin` 替换为您在第二步中下载的语音模型文件的实际路径。\\n\\n例如，如果您的模型文件保存在 Downloads 文件夹中：\\n\\n```bash\\nwhisper-server --model ~/Downloads/ggml-small.bin\\n```\\n\\n### 使用界面\\n\\n命令执行成功后，服务会监听端口 **9001**。\\n\\n在浏览器中打开 `http://localhost:9001` 即可看到界面。\\n\\n![alt text](blog-imgs/macOS安装whisper进行语音识别/image.png)\\n\\n界面非常简洁，您需要做的所有事情包括：\\n\\n1. 选择一个语音文件\\n2. 选择需要的文件输出格式\\n3. 点击 **Submit** 按钮\\n\\n### 输出格式选项\\n\\nWhisper 支持多种输出格式：\\n\\n- **TXT** - 纯文本格式\\n- **VTT** - WebVTT 字幕格式\\n- **SRT** - 标准字幕格式\\n- **JSON** - JSON 格式\\n- **CSV** - CSV 表格格式\\n\\n## 实际应用示例\\n\\n让我们用一个音频文件演示整个使用过程。\\n\\n### 准备工作\\n\\n1. 准备要转录的音频文件\\n2. 启动 whisper-server\\n3. 访问 `http://localhost:9001`\\n\\n### 操作流程\\n\\n1. 在界面上选择音频文件\\n2. 选择输出格式（例如 SRT）\\n3. 点击 Submit\\n\\n<!-- ![alt text](../public/blog-imgs/macOS安装whisper进行语音识别/image-3.png) -->\\n\\n### 结果验证\\n\\n- 识别准确性通常很高\\n- 处理速度快\\n- 支持多种音频格式\\n\\n### 与视频编辑软件结合\\n\\n生成的字幕文件可以导入到各种视频编辑软件中，例如剪映：\\n\\n1. 导出 SRT 字幕文件\\n2. 打开视频编辑软件（如剪映）\\n3. 导入音频文件\\n4. 导入生成的字幕文件\\n5. 调整字幕样式和位置\\n\\n\\n## 总结\\n\\n这种使用 Whisper 生成字幕的方法具有以下优点：\\n\\n- **免费**：无需付费使用\\n- **准确**：中文识别准确率高\\n- **灵活**：支持多种输出格式\\n- **高效**：处理速度快\\n\\n这种方式完美解决了普通用户自动生成字幕的需求。如果您觉得这个方法有用，请点赞关注我，我会持续分享更多实用技巧。\\n\\n## 常见问题\\n\\n### Q: 安装过程中遇到网络问题怎么办？\\n\\nA: 可以尝试重试，或使用网络加速工具。\\n\\n### Q: 模型文件应该选择哪个？\\n\\nA: 对于一般用途，推荐 small 模型；对精度要求高可选择 medium 或 large。\\n\\n### Q: 如何提高识别准确度？\\n\\nA: 选择更大的模型，或对原始音频进行降噪处理。","lastUpdated":1778579020333}]'),u=["href"],S={__name:"BlogList",setup(p){const s=l.filter(n=>n.title!=="index");return console.log(l),(n,_)=>(a(),r("ul",null,[(a(!0),r(g,null,h(c(s),t=>(a(),r("li",{key:t.title},[e("a",{href:`./${t.title}`},o(t.title),9,u),e("span",null,"上次更新： "+o(new Date(t.lastUpdated).toLocaleString()),1)]))),128))]))}},w=m(S,[["__scopeId","data-v-9f36c403"]]),x=JSON.parse('{"title":"博客","description":"","frontmatter":{},"headers":[],"relativePath":"blog/index.md","filePath":"blog/index.md"}'),v={name:"blog/index.md"},B=b({...v,setup(p){return(s,n)=>(a(),r("div",null,[n[0]||(n[0]=e("h1",{id:"博客",tabindex:"-1"},[i("博客 "),e("a",{class:"header-anchor",href:"#博客","aria-label":'Permalink to "博客"'},"​")],-1)),n[1]||(n[1]=e("p",null,"这是我的技术博客页面，记录了我的编程经验、技术思考和项目实践。",-1)),n[2]||(n[2]=e("h2",{id:"文章列表",tabindex:"-1"},[i("文章列表 "),e("a",{class:"header-anchor",href:"#文章列表","aria-label":'Permalink to "文章列表"'},"​")],-1)),d(w)]))}});export{x as __pageData,B as default};
